package main

import (
    "fmt"
    "io"
    "net/http"
    "os"
)

func uploadFile(w http.ResponseWriter, r *http.Request) {
    // Maximum upload of 10 MB files
    r.ParseMultipartForm(10 << 20)
    
    file, handler, err := r.FormFile("myFile")
    if err != nil {
        fmt.Println("Error Retrieving the File")
        fmt.Println(err)
        return
    }
    defer file.Close()

    // Create a new file in the uploads directory that follows the pattern: "upload-{UNIX timestamp}.extension"
    f, err := os.OpenFile("./uploads/"+handler.Filename, os.O_WRONLY|os.O_CREATE, 0666)
    if err != nil {
        fmt.Println(err)
        return
    }
    defer f.Close()
    
    // Write the file to the filesystem at the specified destination
    _, err = io.Copy(f, file)
    if err != nil {
        fmt.Fprintf(w, "Error while saving the file")
        return
    }
    
    // Return the file path of the uploaded file
    fmt.Fprintf(w, "/uploads/"+handler.Filename)
}

func main() {
    http.HandleFunc("/upload", uploadFile)
    http.ListenAndServe(":8080", nil)
}